using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // --- FormatPhoneNumber ---

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParentheses()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.StartsWith("(555)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith("4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesExpectedPattern()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.MatchesRegex(@"^\(\d{3}\) \d{3}-\d{4}$", result);
    }

    [TestMethod]
    [DataRow("5551234567", "(555) 123-4567")]
    [DataRow("8005551212", "(800) 555-1212")]
    [DataRow("0000000000", "(000) 000-0000")]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber(string input, string expected)
    {
        var result = _formatter.FormatPhoneNumber(input);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Null_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));

        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string digits)
    {
        var ex = Assert.ThrowsExactly<ArgumentException>(() => _formatter.FormatPhoneNumber(digits));

        Assert.AreEqual("digits", ex.ParamName);
    }

    // --- BuildGreeting ---

    [TestMethod]
    public void BuildGreeting_WithName_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith("Dear", result);
    }

    [TestMethod]
    public void BuildGreeting_WithName_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_WithNameAndTitle_ContainsTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.Contains("Dr.", result);
    }

    [TestMethod]
    public void BuildGreeting_WithNameAndTitle_ContainsName()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.Contains("Johnson", result);
    }

    [TestMethod]
    [DataRow("Smith", "Mr.", "Dear Mr. Smith,")]
    [DataRow("Jones", "Ms.", "Dear Ms. Jones,")]
    [DataRow("Lee", "Dr.", "Dear Dr. Lee,")]
    public void BuildGreeting_WithNameAndTitle_ReturnsExpected(string name, string title, string expected)
    {
        var result = _formatter.BuildGreeting(name, title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_UsesMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.Contains("Mr.", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhitespaceName_Throws(string? name)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.BuildGreeting(name!));
    }

    // --- GenerateSlug ---

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseWithHyphens()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_Result_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("My Blog Post Title!");

        Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_StripsNonAlphanumeric()
    {
        var result = _formatter.GenerateSlug("C# is Great!!!");

        Assert.AreEqual("c-is-great", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithLeadingTrailingSpaces_TrimsResult()
    {
        var result = _formatter.GenerateSlug("  Padded Title  ");

        Assert.StartsWith("p", result);
        Assert.EndsWith("e", result);
        Assert.AreEqual("padded-title", result);
    }

    [TestMethod]
    [DataRow("Hello World", "hello-world")]
    [DataRow("MSTest 3.x Rocks!", "mstest-3-x-rocks")]
    [DataRow("already-slugged", "already-slugged")]
    [DataRow("UPPER CASE", "upper-case")]
    public void GenerateSlug_VariousTitles_ReturnsExpectedSlug(string title, string expected)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhitespace_Throws(string? title)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.GenerateSlug(title!));
    }

    // --- FormatCurrency ---

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_EuroSymbol_StartsWithEuro()
    {
        var result = _formatter.FormatCurrency(42.50m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_AlwaysShowsTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(100m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    public void FormatCurrency_FractionalAmount_ShowsTwoDecimals()
    {
        var result = _formatter.FormatCurrency(19.9m);

        Assert.EndsWith(".90", result);
    }

    [TestMethod]
    public void FormatCurrency_Amount_MatchesPattern()
    {
        var result = _formatter.FormatCurrency(1234.56m, "$");

        Assert.MatchesRegex(@"^\$\d+\.\d{2}$", result);
    }

    [TestMethod]
    [DataRow("9.99", "$", "$9.99")]
    [DataRow("0", "$", "$0.00")]
    [DataRow("100", "€", "€100.00")]
    [DataRow("-5.5", "$", "$-5.50")]
    public void FormatCurrency_VariousAmounts_ReturnsExpected(string amount, string symbol, string expected)
    {
        var result = _formatter.FormatCurrency(decimal.Parse(amount), symbol);

        Assert.AreEqual(expected, result);
    }
}

